import random

def get_horseman_attributes():
    horsemen = [
        {"name": "Conquest", "horse_color": "white", "weapon": "bow", "symbol": "crown"},
        {"name": "War", "horse_color": "red", "weapon": "sword", "symbol": "conflict"},
        {"name": "Famine", "horse_color": "black", "weapon": "scales", "symbol": "scarcity"},
        {"name": "Death", "horse_color": "pale", "weapon": "authority", "symbol": "mortality"}
    ]
    return horsemen

# Example usage
for horseman in get_horseman_attributes():
    print(f"{horseman['name']}: rides a {horseman['horse_color']} horse, carries a {horseman['weapon']}, symbolizing {horseman['symbol']}.")
